node Place {
    has name: str;
    has value: int;
}

walker SumReachable {
    has total: int = 0;

    can start with `root entry {
        visit [-->];
    }

    can add_place with Place entry {
        self.total += here.value;
        visit [-->];
    }

    can report with `root exit {
        print(self.total);
    }
}

with entry {
    alpha = Place(name="alpha", value=3);
    beta = Place(name="beta", value=5);
    gamma = Place(name="gamma", value=7);
    delta = Place(name="delta", value=11);

    root ++> alpha;
    alpha ++> beta;
    alpha ++> gamma;
    beta ++> delta;

    SumReachable() spawn root;
}

python_code:
graph = {
    "alpha": ["beta", "gamma"],
    "beta": ["delta"],
    "gamma": [],
    "delta": []
}
values = {"alpha": 3, "beta": 5, "gamma": 7, "delta": 11}

def sum_reachable(start, seen=None):
    if seen is None:
        seen = set()
    if start in seen:
        return 0
    seen.add(start)
    total = values[start]
    for nxt in graph[start]:
        total += sum_reachable(nxt, seen)
    return total

print(sum_reachable("alpha"))
